public class Solution {
    public int MinCost(int[][] costs) {

        var colors = 3;
        var houses = costs.Length;

        var dp = new (int cost, int first_color)[colors];

        for(var i = 0; i < houses; i++) {

            var prev = new (int cost, int first_color)[colors];
            Array.Copy(dp, prev, colors);

            for(var j = 0; j < colors; j++) {
                // other two colors
                int n1 = (j + 1) % colors;
                int n2 = (j + 2) % colors;

                // min cost for other two colors
                int c1 = 0, c2 = 0;
                // first color, for other two colors
                int fc1 = n1, fc2 = n2;

                if(i - 1 >= 0) {
                    c1 = prev[n1].cost;
                    c2 = prev[n2].cost;
                    fc1 = prev[n1].first_color;
                    fc2 = prev[n2].first_color;
                }                

                var decided_cost = c1 < c2 ? c1 : c2;
                var decided_first_color = c1 < c2 ? fc1 : fc2;

                dp[j] = (
                    cost: costs[i][j] + decided_cost, 
                    first_color: decided_first_color
                );
            }
        }

        var totalCosts = new int[colors];

        for(var last_color = 0; last_color < colors; last_color++) {
            var data = dp[last_color];

            // original question answer
            totalCosts[last_color] = data.cost;

            // // follow up question answer
            // totalCosts[last_color] = last_color != data.first_color 
            //     ? data.cost 
            //     : int.MaxValue;
        }

        return totalCosts.Min();
    }  


}
